import { Link } from 'react-router-dom';
import { useState } from 'react';
import './Navbar.css';

const Navbar = () => {
  const [isLoggedIn, setIsLoggedIn] = useState(false);

  return (
    <nav className="navbar">
      <div className="nav-container">
        <Link to="/" className="nav-logo">
          <span className="logo-text">मंचित्र</span>
          <span className="logo-subtext">Manchitra</span>
        </Link>

        <div className="search-bar">
          <input 
            type="text" 
            placeholder="Search for mandaps and services..."
            className="search-input"
          />
          <button className="search-button">
            <i className="fas fa-search"></i>
          </button>
        </div>

        <div className="nav-links">
          <Link to="/" className="nav-link">Home</Link>
          <Link to="/mandaps" className="nav-link">Mandaps</Link>
          <Link to="/services" className="nav-link">Nearby Services</Link>
          <Link to="/contribute" className="nav-link">Contribute</Link>
          <Link to="/about" className="nav-link">About Us</Link>
          {isLoggedIn ? (
            <div className="user-menu">
              <button className="user-button">
                <i className="fas fa-user"></i>
              </button>
            </div>
          ) : (
            <button className="sign-in-btn">Sign In</button>
          )}
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
